function uuidv4() {
  if (globalThis.crypto && typeof crypto.randomUUID === 'function') return crypto.randomUUID();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

function labelNames(labels) {
  if (!Array.isArray(labels)) return [];
  return labels.map(l => typeof l === 'string' ? l : (l && l.name)).filter(Boolean);
}

function tenantFromLabels(labels) {
  const hit = labelNames(labels).find(l => /^tenant:/i.test(l));
  return hit ? hit.split(':').slice(1).join(':') : null;
}

function priorityFromLabels(labels) {
  const names = labelNames(labels).map(l => l.toLowerCase());
  if (names.includes('p0') || names.includes('critical')) return 'P0';
  if (names.includes('p1') || names.includes('high')) return 'P1';
  if (names.includes('p2')) return 'P2';
  return 'P3';
}

function ageHours(createdAt) {
  const t = createdAt ? Date.parse(createdAt) : NaN;
  if (!Number.isFinite(t)) return 0;
  return Math.max(0, Math.round((Date.now() - t) / 36e5));
}

const root = $input.first().json || {};
let body = root.body || root;
// Replay payloads may carry the full webhook envelope ({headers,query,body}); unwrap it.
if (body && typeof body === 'object' && body.body && typeof body.body === 'object' && (body.headers || body.query || body.webhookUrl)) body = body.body;
const replay = !!root.replay;
const response_required = !!root.body && !replay;
const configuredRepo = body.repo || $env.GITHUB_REPO || '';
const thresholdHours = Number(body.sla_hours || $env.GITHUB_SLA_HOURS || 48);
const label = body.label || $env.GITHUB_SLA_LABEL || 'sla-watch';
let issue = body.issue || body;

const wantsScan = body.mode === 'scan' || (!root.body && !replay);
if (wantsScan) {
  if (!configuredRepo || !$env.GITHUB_TOKEN) return [];
  const q = 'repo:' + configuredRepo + ' is:issue is:open label:"' + label + '" sort:created-asc';
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://api.github.com/search/issues',
    qs: { q, per_page: 20 },
    headers: { Authorization: 'Bearer ' + $env.GITHUB_TOKEN, Accept: 'application/vnd.github+json', 'User-Agent': 'flowops-n8n' },
    json: true
  });
  const breached = (res.items || []).filter(i => ageHours(i.created_at) >= thresholdHours);
  // Only emit issues with a resolvable tenant (tenant:<uuid> label); an unlabeled breached
  // issue would throw at Prep Idempotency on every 30-min scan and spam the DLQ via G1.
  const actionable = breached.filter(i => tenantFromLabels(i.labels || []));
  if (actionable.length === 0) return [];
  issue = actionable[0];
}

const labels = issue.labels || body.labels || [];
const tenant_id = body.tenant_id || issue.tenant_id || tenantFromLabels(labels) || root.tenant_id || null;
const repo = body.repo || issue.repository_url?.split('/repos/')[1] || configuredRepo || null;
const issue_number = body.issue_number || issue.number || issue.issue_number || null;
const issue_url = body.issue_url || issue.html_url || issue.url || null;
const title = body.title || issue.title || 'Support issue nearing SLA breach';
const created_at = body.created_at || issue.created_at || null;
const updated_at = body.updated_at || issue.updated_at || null;
const age_h = Number(body.age_h != null ? body.age_h : ageHours(created_at));
const priority = body.priority || priorityFromLabels(labels);
const assignee = body.assignee || (issue.assignee && issue.assignee.login) || (Array.isArray(issue.assignees) && issue.assignees[0] && issue.assignees[0].login) || null;
const source = replay ? 'replay' : (wantsScan ? 'github-scan' : (body.source || 'github-webhook'));
const event_id = body.event_id || issue.node_id || issue.id || (repo && issue_number ? repo + '#' + issue_number + ':' + (updated_at || created_at || '') : null);
// Scan-found breaches bucket by day so a still-breached issue re-alerts daily instead of never again.
const dayBucket = new Date().toISOString().slice(0, 10);
const idem_key = 'sla:' + (event_id || (tenant_id + ':' + issue_number + ':' + age_h)) + (wantsScan ? ':' + dayBucket : '');
const correlation_id = replay && root.correlation_id ? root.correlation_id : uuidv4();

return [{ json: {
  tenant_id,
  repo,
  issue_number,
  issue_url,
  title,
  labels: labelNames(labels),
  created_at,
  updated_at,
  age_h,
  sla_hours: thresholdHours,
  priority,
  assignee,
  source,
  replay,
  response_required,
  event_id,
  idem_key,
  correlation_id,
  execution_id: String($execution.id),
  supabase_url: ($env.SUPABASE_URL || '').replace(/\/$/, '')
} }];

const p = $('Normalize Issue').first().json;
if (!p.tenant_id) throw new Error('sla: missing tenant_id (pass tenant_id or a tenant:<uuid> GitHub label)');
return [{ json: { key: p.idem_key, tenant_id: p.tenant_id, workflow: '07-support-sla-escalation' } }];

const p = $('Normalize Issue').first().json;
const pol = $('Resolve Policy').first().json;
return [{ json: { tenant_id: p.tenant_id, correlation_id: p.correlation_id, service: 'sla', step: 'approve-escalation', status: 'waiting', payload: { tenant_name: pol.tenant_name, repo: p.repo, issue_number: p.issue_number, issue_url: p.issue_url, title: p.title, priority: p.priority, age_h: p.age_h, approver: pol.policy.approval.approver } } }];

const p = $('Normalize Issue').first().json;
const pol = $('Resolve Policy').first().json;
const text = [
  'Support SLA escalation needed',
  'Tenant: ' + (pol.tenant_name || p.tenant_id) + ' (' + (pol.plan || 'unknown') + ')',
  'Issue: #' + p.issue_number + ' ' + p.title,
  'Priority: ' + p.priority + ' | Age: ' + p.age_h + 'h',
  'Approver: ' + pol.policy.approval.approver,
  'Correlation: `' + p.correlation_id + '`'
].join('\n');
let alert_delivered = false;
let notice = null;
const token = $env.TELEGRAM_BOT_TOKEN;
const chat = $env.TELEGRAM_CHAT_ID;
if (token && chat) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot' + token + '/sendMessage',
      body: {
        chat_id: chat,
        text,
        parse_mode: 'Markdown',
        reply_markup: { inline_keyboard: [[ { text: 'Approve', url: $execution.resumeUrl + '?decision=approve' }, { text: 'Reject', url: $execution.resumeUrl + '?decision=reject' } ]] }
      },
      json: true
    });
    alert_delivered = true;
  } catch (e) {
    notice = 'telegram failed: ' + (e && e.message ? e.message : String(e));
  }
} else {
  notice = 'telegram skipped: TELEGRAM_BOT_TOKEN / TELEGRAM_CHAT_ID not set';
}
return [{ json: { alert_delivered, notice } }];

const p = $('Normalize Issue').first().json;
const pol = $('Resolve Policy').first().json;
let github_comment_delivered = false;
let notice = null;
if ($env.GITHUB_TOKEN && p.repo && p.issue_number) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.github.com/repos/' + p.repo + '/issues/' + p.issue_number + '/comments',
      headers: { Authorization: 'Bearer ' + $env.GITHUB_TOKEN, Accept: 'application/vnd.github+json', 'User-Agent': 'flowops-n8n' },
      body: { body: 'FlowOps SLA escalation approved for ' + (pol.tenant_name || p.tenant_id) + '. Correlation: ' + p.correlation_id },
      json: true
    });
    github_comment_delivered = true;
  } catch (e) {
    notice = 'github comment failed: ' + (e && e.message ? e.message : String(e));
  }
} else {
  notice = 'github comment skipped: GITHUB_TOKEN/repo/issue missing';
}
return [{ json: { tenant_id: p.tenant_id, correlation_id: p.correlation_id, github_comment_delivered, notice } }];

const p = $('Normalize Issue').first().json;
const pol = $('Resolve Policy').first().json;
const gh = $('Post GitHub Escalation Comment').first().json;
return [{ json: { tenant_id: p.tenant_id, correlation_id: p.correlation_id, service: 'sla', step: 'approve-escalation', status: 'success', payload: { decision: 'approved', tenant_name: pol.tenant_name, repo: p.repo, issue_number: p.issue_number, assignee: p.assignee, github_comment_delivered: gh.github_comment_delivered, notice: gh.notice } } }];
